// ─── LOADER ───────────────────────────────────────────────────────────────────
function Loader({ onDone }) {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const interval = setInterval(() => {
      setPct(p => {
        if (p >= 100) { clearInterval(interval); setTimeout(onDone, 400); return 100; }
        return p + Math.random()*8+2;
      });
    }, 60);
    return () => clearInterval(interval);
  }, [onDone]);
  return (
    <div style={{ position:"fixed", inset:0, background:var_bg, zIndex:9999, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", animation: pct===100 ? "fadeOut .4s .4s forwards" : "none" }}>
      <style>{`@keyframes fadeOut{to{opacity:0;pointer-events:none}}`}</style>
      <div style={{ fontFamily:"'Syne',sans-serif", fontSize:"clamp(2rem,5vw,4rem)", fontWeight:800, marginBottom:40 }}>
        <span style={{ background:"linear-gradient(135deg,#8B5CF6,#3B82F6,#EC4899)", WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent", backgroundClip:"text" }}>DHANUSH K</span>
      </div>
      <div style={{ width:300, height:2, background:"rgba(255,255,255,.1)", borderRadius:2, overflow:"hidden" }}>
        <div style={{ height:"100%", width:`${pct}%`, background:"linear-gradient(90deg,#8B5CF6,#3B82F6,#EC4899)", transition:"width .1s", borderRadius:2 }} />
      </div>
      <div style={{ marginTop:16, color:"rgba(148,163,184,.6)", fontSize:12, fontFamily:"'DM Sans',sans-serif", letterSpacing:".2em" }}>
        LOADING {Math.min(100,Math.round(pct))}%
      </div>
    </div>
  );
}
