// ─── SCROLL PROGRESS BAR ──────────────────────────────────────────────────────
function ScrollProgress() {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const s = () => {
      const total = document.body.scrollHeight - window.innerHeight;
      setPct((window.scrollY/total)*100);
    };
    window.addEventListener("scroll", s);
    return () => window.removeEventListener("scroll", s);
  }, []);
  return (
    <div style={{ position:"fixed", top:0, left:0, right:0, height:2, zIndex:1001 }}>
      <div style={{ height:"100%", width:`${pct}%`, background:"linear-gradient(90deg,#8B5CF6,#3B82F6,#EC4899)", transition:"width .1s" }} />
    </div>
  );
}

