// ─── PROJECT CARD ─────────────────────────────────────────────────────────────
function ProjectCard({ p, index, vis }) {
  const [tilt, setTilt] = useState({ x:0, y:0 });
  const [hovered, setHovered] = useState(false);

  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientY - rect.top) / rect.height - .5) * 15;
    const y = ((e.clientX - rect.left) / rect.width - .5) * -15;
    setTilt({ x, y });
  };

  return (
    <div
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setTilt({x:0,y:0}); setHovered(false); }}
      style={{
        opacity:vis?1:0, transform:`perspective(1000px) rotateX(${tilt.x}deg) rotateY(${tilt.y}deg) ${vis?"":"translateY(40px)"}`,
        transition:`opacity .8s ${index*.1}s, transform .3s`,
        background:"rgba(255,255,255,.03)",
        border:`1px solid ${hovered ? p.color+"44" : "rgba(255,255,255,.08)"}`,
        borderRadius:20, padding:32,
        boxShadow: hovered ? `0 20px 60px ${p.color}22, 0 0 30px ${p.color}15` : "none",
        cursor:"pointer",
      }}
    >
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:20 }}>
        <div style={{ fontSize:"2.5rem", animation: hovered?"float 3s ease-in-out infinite":"none" }}>{p.icon}</div>
        <a href={p.github} style={{
          background:`${p.color}22`, border:`1px solid ${p.color}44`,
          color:"#fff", padding:"6px 14px", borderRadius:8,
          textDecoration:"none", fontSize:"0.8rem",
          fontFamily:"'DM Sans',sans-serif", fontWeight:500,
          transition:"all .3s",
          boxShadow: hovered ? `0 0 15px ${p.color}44` : "none",
        }}>GitHub ↗</a>
      </div>
      <h3 style={{ fontFamily:"'Syne',sans-serif", fontWeight:700, fontSize:"1.15rem", marginBottom:12, color:"#F1F5F9" }}>{p.title}</h3>
      <p style={{ color:"#64748B", fontSize:"0.9rem", lineHeight:1.7, marginBottom:20 }}>{p.desc}</p>
      <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
        {p.tags.map(t => (
          <span key={t} style={{
            background:`${p.color}15`, border:`1px solid ${p.color}30`,
            color:p.color, padding:"3px 10px", borderRadius:6,
            fontSize:"0.75rem", fontFamily:"'DM Sans',sans-serif", fontWeight:500,
          }}>{t}</span>
        ))}
      </div>
    </div>
  );
}

