// ─── CONTACT SECTION ──────────────────────────────────────────────────────────
function ContactSection() {
  const [form, setForm] = useState({ name: "", email: "", confirmEmail: "", message: "" });
  const [status, setStatus] = useState("idle");
  const [isEmailLocked, setIsEmailLocked] = useState(false);
  const ref = useRef(null);
  const [vis, setVis] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: .1 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  // Validation Logic
  const emailsMatch = form.email === form.confirmEmail;
  const isFormValid = 
    form.name.trim() !== "" && 
    form.email.includes("@") && 
    emailsMatch && 
    form.message.trim() !== "";

  const submit = async () => {
    if (!isFormValid) return;
    setStatus("sending");

    try {
      const formData = new FormData();
      formData.append("access_key", "95d99085-993f-452c-8d98-e7087f26c8ba");
      formData.append("name", form.name);
      formData.append("email", form.email);
      formData.append("message", form.message);

      const response = await fetch("https://api.web3forms.com/submit", {
        method: "POST",
        body: formData
      });

      const data = await response.json();

      if (data.success) {
        setStatus("success");
        setTimeout(() => { 
          setStatus("idle"); 
          setForm({ name: "", email: "", confirmEmail: "", message: "" }); 
          setIsEmailLocked(false);
        }, 3000);
      } else {
        setStatus("error");
        setTimeout(() => setStatus("idle"), 3000);
      }
    } catch (error) {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  };

  const inputStyle = (focused, hasError) => ({
    width: "100%", padding: "14px 18px", borderRadius: 12,
    background: "rgba(255,255,255,.05)", color: "#F1F5F9",
    border: `1px solid ${hasError ? "#EF4444" : focused ? "rgba(139,92,246,.5)" : "rgba(255,255,255,.1)"}`,
    outline: "none", fontFamily: "'DM Sans',sans-serif", fontSize: "0.95rem",
    transition: "all .3s", boxSizing: "border-box",
    boxShadow: hasError ? "0 0 15px rgba(239,68,68,.1)" : focused ? "0 0 20px rgba(139,92,246,.15)" : "none",
  });

  return (
    <section id="contact" className="section" ref={ref}>
      <div className="container">
        <div style={{ maxWidth: 720, margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: 64 }}>
            <div className="section-label">Get In Touch</div>
            <h2 className="section-title" style={{ textAlign: "center" }}>Let's Build Something <span className="gradient-text">Together</span></h2>
            <p style={{ color: "#64748B", textAlign: "center", marginTop: 16 }}>Have a project in mind or want to discuss data? I'm just one message away.</p>
          </div>

          <div className="glass" style={{
            padding: 48,
            opacity: vis ? 1 : 0, transform: vis ? "none" : "translateY(40px)",
            transition: "opacity 1s, transform 1s",
          }}>
            {status === "success" ? (
              <div style={{ textAlign: "center", padding: "40px 0" }}>
                <div style={{ fontSize: "4rem", marginBottom: 16 }}>✅</div>
                <div style={{ fontFamily: "'Syne',sans-serif", fontWeight: 700, fontSize: "1.5rem", marginBottom: 8 }}>Message Sent!</div>
                <div style={{ color: "#64748B" }}>I'll get back to you within 24 hours.</div>
              </div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
                  <FocusInput label="Your Name" value={form.name} onChange={v => setForm(f => ({ ...f, name: v }))} placeholder="John Doe" inputStyle={inputStyle} />
                  
                  {!isEmailLocked ? (
                    <FocusInput 
                      label="Email Address" 
                      type="email" 
                      value={form.email} 
                      onChange={v => setForm(f => ({ ...f, email: v }))} 
                      placeholder="john@example.com" 
                      inputStyle={inputStyle}
                      onBlur={() => { if(form.email.includes("@")) setIsEmailLocked(true); }}
                    />
                  ) : (
                    <div>
                      <FocusInput 
                        label="Confirm Your Email Address" 
                        type="email" 
                        value={form.confirmEmail} 
                        onChange={v => setForm(f => ({ ...f, confirmEmail: v }))} 
                        placeholder="************" 
                        inputStyle={inputStyle}
                        hasError={form.confirmEmail.length > 0 && !emailsMatch}
                      />
                      {/* RED ERROR MESSAGE */}
                      {form.confirmEmail.length > 0 && !emailsMatch && (
                        <p style={{ color: "#EF4444", fontSize: "0.75rem", marginTop: 6, marginLeft: 4 }}>
                          The email does not match the previous one
                        </p>
                      )}
                    </div>
                  )}
                </div>
                
                <div>
                  <label style={{ display: "block", marginBottom: 8, color: "#94A3B8", fontSize: "0.9rem" }}>Message</label>
                  <FocusTextarea value={form.message} onChange={v => setForm(f => ({ ...f, message: v }))} placeholder="Tell me about your project or inquiry..." inputStyle={inputStyle} />
                </div>

                <button 
                  onClick={submit} 
                  disabled={!isFormValid || status === "sending"} 
                  style={{
                    background: isFormValid ? "linear-gradient(135deg,#8B5CF6,#3B82F6)" : "rgba(255,255,255,0.08)", 
                    color: isFormValid ? "#fff" : "#64748B",
                    border: "none", padding: "16px 40px", borderRadius: 12,
                    fontFamily: "'Syne',sans-serif", fontWeight: 700, fontSize: "1rem",
                    cursor: isFormValid ? "pointer" : "not-allowed", 
                    transition: "all .3s", alignSelf: "flex-start",
                    boxShadow: isFormValid ? "0 0 30px rgba(139,92,246,.4)" : "none",
                    opacity: status === "sending" ? .7 : 1,
                  }}
                  onMouseEnter={e => { if(isFormValid) { e.target.style.transform = "translateY(-2px)"; e.target.style.boxShadow = "0 0 50px rgba(139,92,246,.6)"; } }}
                  onMouseLeave={e => { e.target.style.transform = "none"; e.target.style.boxShadow = isFormValid ? "0 0 30px rgba(139,92,246,.4)" : "none"; }}
                >
                  {status === "sending" ? "Sending..." : isFormValid ? "Send Message →" : "Verify Email to Enable"}
                </button>
              </div>
            )}
          </div>

          <div style={{ display: "flex", justifyContent: "center", gap: 16, marginTop: 48, flexWrap: "wrap" }}>
            {[
              { icon: "💼", label: "LinkedIn", url: "https://www.linkedin.com/in/dhanushba/", color: "#0A66C2" },
              { icon: "🐙", label: "GitHub", url: "https://github.com/dhanushk21", color: "#fff" },
              { icon: "📸", label: "Instagram", url: "https://www.instagram.com/dhanushh_07/", color: "#E1306C" },
            ].map(s => (
              <a key={s.label} href={s.url} target="_blank" rel="noreferrer" style={{
                display: "flex", flexDirection: "column", alignItems: "center", gap: 8,
                background: "rgba(255,255,255,.04)", border: "1px solid rgba(255,255,255,.08)",
                borderRadius: 16, padding: "16px 24px", textDecoration: "none",
                transition: "all .3s",
              }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = s.color + "44"; e.currentTarget.style.boxShadow = `0 0 25px ${s.color}33`; e.currentTarget.style.transform = "translateY(-4px)"; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = "rgba(255,255,255,.08)"; e.currentTarget.style.boxShadow = "none"; e.currentTarget.style.transform = "none"; }}
              >
                <span style={{ fontSize: "1.5rem" }}>{s.icon}</span>
                <span style={{ color: "#64748B", fontSize: "0.8rem", fontFamily: "'DM Sans',sans-serif" }}>{s.label}</span>
              </a>
            ))}
          </div>
        </div>
      </div>
      <style>{`@media(max-width:768px){#contact .glass>div>div:first-child{grid-template-columns:1fr!important}}`}</style>
    </section>
  );
}

function FocusInput({ label, value, onChange, placeholder, type = "text", inputStyle, onBlur, hasError }) {
  const [focused, setFocused] = useState(false);
  return (
    <div>
      <label style={{ display: "block", marginBottom: 8, color: "#94A3B8", fontSize: "0.9rem" }}>{label}</label>
      <input
        type={type} value={value} placeholder={placeholder}
        onChange={e => onChange(e.target.value)}
        onFocus={() => setFocused(true)} 
        onBlur={(e) => { setFocused(false); if(onBlur) onBlur(e); }}
        style={inputStyle(focused, hasError)}
      />
    </div>
  );
}

function FocusTextarea({ value, onChange, placeholder, inputStyle }) {
  const [focused, setFocused] = useState(false);
  return (
    <textarea
      value={value} placeholder={placeholder} rows={6}
      onChange={e => onChange(e.target.value)}
      onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
      style={{ ...inputStyle(focused), resize: "vertical" }}
    />
  );
}

// ─── FOOTER ───────────────────────────────────────────────────────────────────
function Footer() {
  return (
    <footer style={{ borderTop:"1px solid rgba(255,255,255,.06)", padding:"40px 0", textAlign:"center" }}>
      <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:"1.5rem", marginBottom:12 }}>
        <span style={{ background:"linear-gradient(135deg,#8B5CF6,#3B82F6,#EC4899)", WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent", backgroundClip:"text" }}>DHANUSH K</span>
      </div>
      <div style={{ color:"#334155", fontSize:"0.85rem" }}>
        © 2026 Dhanush K — Data Analyst | Business Analyst
      </div>
      <div style={{ color:"#97accf", fontSize:"0.99rem", marginTop:8 }}>
        with ❤️ and lots of data
      </div>
    </footer>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [loaded, setLoaded] = useState(false);
  const [active, setActive] = useState("Home");

  useEffect(() => {
    const styleEl = document.createElement("style");
    styleEl.textContent = globalCSS;
    document.head.appendChild(styleEl);
    return () => document.head.removeChild(styleEl);
  }, []);

  // Intersection-based active nav
  useEffect(() => {
    const obs = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          const id = e.target.id;
          const match = NAV_ITEMS.find(n => n.toLowerCase() === id);
          if (match) setActive(match);
        }
      });
    }, { threshold:.3 });
    NAV_ITEMS.forEach(n => {
      const el = document.getElementById(n.toLowerCase());
      if (el) obs.observe(el);
    });
    return () => obs.disconnect();
  }, [loaded]);

  return (
    <div style={{ background:var_bg, minHeight:"100vh", position:"relative" }}>
      {!loaded && <Loader onDone={() => setLoaded(true)} />}
      {loaded && (
        <>
          <style>{`@keyframes fadeIn{from{opacity:0}to{opacity:1}}`}</style>
          <div style={{ animation:"fadeIn .8s ease forwards" }}>
            <Cursor />
            <ParticleCanvas />
            <FloatingOrbs />
            <ScrollProgress />
            <Navbar active={active} setActive={setActive} />
            <HeroSection />
            <AboutSection />
            <SkillsSection />
            <ProjectsSection />
            <ProfilesSection />
            <ContactSection />
            <Footer />
          </div>
        </>
      )}
    </div>
  );
}
